package ua.university.sms.service;import org.springframework.stereotype.Service;import ua.university.sms.exception.NotFoundException;import ua.university.sms.model.dto.TeacherDtos.*;import ua.university.sms.model.entity.Teacher;import ua.university.sms.repository.TeacherRepository;import java.util.*;
@Service public class TeacherService{private final TeacherRepository repo;public TeacherService(TeacherRepository r){repo=r;}public Response create(Request d){Teacher t=new Teacher();apply(t,d);return dto(repo.save(t));}public Response get(Long id){return dto(find(id));}public List<Response> list(){return repo.findAll().stream().map(this::dto).toList();}public Response update(Long id,Request d){Teacher t=find(id);apply(t,d);return dto(repo.save(t));}public void delete(Long id){repo.delete(find(id));}Teacher find(Long id){return repo.findById(id).orElseThrow(()->new NotFoundException("Teacher not found: "+id));}private void apply(Teacher t,Request d){t.setFullName(d.fullName());t.setEmail(d.email());t.setDepartment(d.department());}private Response dto(Teacher t){return new Response(t.getId(),t.getFullName(),t.getEmail(),t.getDepartment());}}
